module RefModule (
    input [3:0] A,
    input [3:0] B,
    input Cin,
    input Clk,
    output [3:0] Sum,
    output Cout
);

    reg [3:0] Sum_reg;
    reg Cout_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge Clk or posedge dbg_halt) begin
        {Cout_reg, Sum_reg} <= A + B + Cin;
    end

    assign Sum = Sum_reg;
    assign Cout = Cout_reg;

endmodule
